/*
import React from 'react'

export default function Professors() {
  return (
    <div>
        <h1>Professors</h1>
    </div>
  )
}
*/

import React from 'react';

const Professors = () => {
  return (
    <div>
      <h1>Professors</h1>
    </div>
  );
};

export default Professors;
